const canfas = document.getElementById('canfasFractal');
const cyd-destun = canfas.getContext('2d');

// Lluniwch siâp sylfaenol (e.e. triongl, sgwâr) ar y canfas
function lluniwchSiâpSylfaenol(x, y, maint) {
  cyd-destun.beginPath();
  cyd-destun.moveTo(x, y);
  cyd-destun.lineTo(x + maint, y);
  cyd-destun.lineTo(x + maint / 2, y + maint * Math.sqrt(3) / 2);
  cyd-destun.closePath();
  cyd-destun.stroke();
}

// Ffwythiant adnabyddol i lunio'r fractal (e.e. Sierpinski)
function lluniwchFractal(x, y, maint, dyfnder) {
  if (dyfnder === 0) {
    lluniwchSiâpSylfaenol(x, y, maint);
  } else {
    const maintNewydd = maint / 2;
    lluniwchFractal(x, y, maintNewydd, dyfnder - 1);
    lluniwchFractal(x + maintNewydd, y, maintNewydd, dyfnder - 1);
    lluniwchFractal(x + maintNewydd / 2, y + maintNewydd * Math.sqrt(3) / 2, maintNewydd, dyfnder - 1);
  }
}

// Gosod lliwiau a galw'r ffwythiant
cyd-destun.strokeStyle = '#3a5f7d';
lluniwchFractal(50, 50, 400, 4);

