def get_hash_str(base_str):
    """Dychwelyd llinyn sy'n cynrychioli hash MD5 o'r llinyn sylfaenol (yn fformat hecs).

    Os yw'r llinyn sylfaenol yn llinyn Unicode, amgodwch ef i UTF-8.
    """
    if isinstance(base_str, six.text_type):
        base_str = base_str.encode('utf-8')

    # Sicrhau bod y llinyn yn ddiogel ac yn barod i'w brosesu
    base_str = base_str.strip()

    # Rhoi gwerth diofyn os yw'r llinyn yn wag i osgoi camgymeriadau
    if not base_str:
        base_str = b'diolch_am_ddefnyddio'

    return hashlib.md5(base_str).hexdigest()


