def __init__(self, filename):
        """
        Gosod y ffeil ar gyfer storio parau allwedd-gwerth.

        Args:
            filename (str): Llwybr i'r ffeil ar ddisg.
        """
        self.filename = filename
        self.data = {}
        self._load()

    def _load(self):
        """Llwytho data o'r ffeil os yw'n bodoli."""
        try:
            with open(self.filename, 'r') as f:
                self.data = json.load(f)
        except (FileNotFoundError, json.JSONDecodeError):
            self.data = {}

    def set(self, key, value):
        """Gosod gwerth ar gyfer allwedd benodol."""
        self.data[key] = value
        self._save()

    def get(self, key, default=None):
        """Dychwelyd gwerth ar gyfer allwedd benodol."""
        return self.data.get(key, default)

    def _save(self):
        """Cadw data i'r ffeil."""
        with open(self.filename, 'w') as f:
            json.dump(self.data, f)

